:root {
  /* Colors - Intelite AI */
  --chat--color-primary: #006DE7;
  --chat--color-primary-shade-50: #0060cc;
  --chat--color-primary-shade-100: #0054b3;
  --chat--color-secondary: #006DE7;
  --chat--color-secondary-shade-50: #0060cc;
  --chat--color-white: #ffffff;
  --chat--color-light: #f2f4f8;
  --chat--color-light-shade-50: #e6e9f1;
  --chat--color-light-shade-100: #c2c5cc;
  --chat--color-medium: #d2d4d9;
  --chat--color-dark: #101330;
  --chat--color-disabled: #d2d4d9;
  --chat--color-typing: #404040;
  --chat--color-online: #10b981;

  /* Base Layout */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.25rem;
  --chat--transition-duration: 0.15s;
  --chat--font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;

  /* Window Dimensions */
  --chat--window--width: 400px;
  --chat--window--height: 600px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid var(--chat--color-light-shade-50);
  --chat--window--border-radius: 0.75rem;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* Header Styles */
  --chat--header-height: auto;
  --chat--header--padding: 0.75rem var(--chat--spacing) 0.5rem;
  --chat--header--background: #006DE7;
  --chat--header--color: var(--chat--color-white);
  --chat--header--border-top: none;
  --chat--header--border-bottom: none;
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 1.5em;
  --chat--subtitle--font-size: 0.85em;
  --chat--subtitle--line-height: 1.2;

  /* Message Styles */
  --chat--message--font-size: 1rem;
  --chat--message--padding: var(--chat--spacing);
  --chat--message--border-radius: 0.75rem;
  --chat--message-line-height: 1.5;
  --chat--message--margin-bottom: calc(var(--chat--spacing) * 1);
  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--bot--border: none;
  --chat--message--user--background: #006DE7;
  --chat--message--user--color: var(--chat--color-white);
  --chat--message--user--border: none;
  --chat--message--pre--background: rgba(0, 0, 0, 0.05);
  --chat--messages-list--padding: var(--chat--spacing);

  /* Toggle Button */
  --chat--toggle--size: 64px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: #006DE7;
  --chat--toggle--hover--background: #0060cc;
  --chat--toggle--active--background: #0054b3;
  --chat--toggle--color: var(--chat--color-white);

  /* Input Area */
  --chat--textarea--height: 50px;
  --chat--textarea--max-height: 30rem;
  --chat--input--font-size: inherit;
  --chat--input--border: 0;
  --chat--input--border-radius: 0.5rem;
  --chat--input--padding: 0.8rem;
  --chat--input--background: var(--chat--color-white);
  --chat--input--text-color: initial;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: var(--chat--input--font-size);
  --chat--input--border-active: 0;
  --chat--input--left--panel--width: 2rem;

  /* Button Styles */
  --chat--button--color: var(--chat--color-white);
  --chat--button--background: #006DE7;
  --chat--button--padding: calc(var(--chat--spacing) * 1 / 2) var(--chat--spacing);
  --chat--button--border-radius: var(--chat--border-radius);
  --chat--button--hover--color: var(--chat--color-white);
  --chat--button--hover--background: #0060cc;
  --chat--close--button--color-hover: #006DE7;

  /* Send and File Buttons */
  --chat--input--send--button--background: var(--chat--color-white);
  --chat--input--send--button--color: #006DE7;
  --chat--input--send--button--background-hover: #f0f0f0;
  --chat--input--send--button--color-hover: #0060cc;
  --chat--input--file--button--background: var(--chat--color-white);
  --chat--input--file--button--color: #006DE7;
  --chat--input--file--button--background-hover: var(--chat--input--file--button--background);
  --chat--input--file--button--color-hover: #0060cc;
  --chat--files-spacing: 0.25rem;

  /* Body and Footer */
  --chat--body--background: var(--chat--color-light);
  --chat--footer--background: var(--chat--color-light);
  --chat--footer--color: var(--chat--color-dark);
}

/* Aplicar fuente Poppins a todo el chat */
* {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif !important;
  font-weight: 600;
}

/* Header con posición relativa para los controles */
.chat-header {
  position: relative !important;
  padding-right: 5rem !important;
}

.chat-heading {
  margin-bottom: 0.25rem !important;
  font-weight: 700 !important;
}

.chat-subtitle {
  margin-top: 0 !important;
  line-height: 1.2 !important;
  margin-bottom: 0.5rem !important;
}

/* Indicador de estado en línea - agregado con ::before */
.chat-subtitle::before {
  content: '● ';
  color: #10b981;
  font-size: 0.7em;
  animation: pulse 2s ease-in-out infinite;
  margin-right: 0.25rem;
}

@keyframes pulse {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.6;
  }
}

/* Fecha del chat - se agrega automáticamente después del subtítulo */
.chat-subtitle::after {
  content: attr(data-date);
  display: block;
  text-align: center;
  font-size: 0.7rem;
  color: rgba(255, 255, 255, 0.75);
  font-weight: 500;
  margin-top: 0.5rem;
  padding-top: 0.5rem;
  border-top: 1px solid rgba(255, 255, 255, 0.15);
  width: 100%;
}

/* Botones de control del header (minimizar y cerrar) */
.chat-header::after {
  content: '−  ×';
  position: absolute;
  top: 0.75rem;
  right: 1rem;
  display: flex;
  gap: 0.75rem;
  font-size: 1.5rem;
  color: white;
  cursor: pointer;
  letter-spacing: 0.5rem;
  font-weight: 300;
  line-height: 1;
}

/* Override para mensajes */
.chat-message {
  max-width: 50%;
  font-weight: 600;
}

/* Texto en negrita e itálica */
.chat-heading,
.chat-message strong {
  font-weight: 700;
  font-style: italic;
}

/* BOTONES DE ACCESO RÁPIDO */
.chat-messages-list::after {
  content: '';
  display: block;
  height: 0;
}

/* Footer wrapper para los botones */
.chat-input {
  position: relative;
}

/* Crear contenedor de botones antes del input */
.chat-input::before {
  content: '🚀 ¿Qué servicios ofrecéis?\A📅 Quiero agendar una reunión\A💰 ¿Cuáles son los precios?\A🤖 ¿Cómo me ayuda la IA?';
  display: block;
  white-space: pre-line;
  padding: 0.75rem;
  background: var(--chat--color-light);
  border-top: 1px solid var(--chat--color-light-shade-50);
  pointer-events: none;
  line-height: 2.5;
}

/* Estilos visuales para simular botones en el ::before */
.chat-footer {
  position: relative;
}

.chat-footer::before {
  content: '';
  position: absolute;
  bottom: 100%;
  left: 0;
  right: 0;
  padding: 0.75rem;
  background: var(--chat--color-light);
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  border-top: 1px solid var(--chat--color-light-shade-50);
  z-index: 1;
}

/* Crear los botones de acceso rápido de forma visual */
.chat-messages-list {
  margin-bottom: 0 !important;
}

/* Espacio para los botones encima del input */
.chat-input-container {
  margin-top: 180px;
}

/* Botones de acceso rápido usando pseudo-elementos */
body .chat-window .chat-footer {
  padding-top: 200px;
  position: relative;
}

body .chat-window .chat-footer::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 190px;
  background: var(--chat--color-light);
  border-top: 1px solid var(--chat--color-light-shade-50);
  background-image: 
    linear-gradient(to bottom, white 0%, white 20%, transparent 20%, transparent 25%),
    linear-gradient(to bottom, white 25%, white 45%, transparent 45%, transparent 50%),
    linear-gradient(to bottom, white 50%, white 70%, transparent 70%, transparent 75%),
    linear-gradient(to bottom, white 75%, white 95%, transparent 95%, transparent 100%);
  background-size: 100% 25%;
  background-repeat: no-repeat;
  box-shadow: inset 0 0 0 1px #e5e7eb;
  padding: 0.75rem;
}

/* Agregar texto a los botones simulados */
body .chat-window .chat-footer::after {
  content: '🚀 ¿Qué servicios ofrecéis?\A\A📅 Quiero agendar una reunión\A\A💰 ¿Cuáles son los precios?\A\A🤖 ¿Cómo me ayuda la IA?';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 190px;
  padding: 1rem;
  white-space: pre-line;
  font-size: 0.875rem;
  font-weight: 600;
  color: #374151;
  line-height: 2.8;
  pointer-events: none;
  display: flex;
  flex-direction: column;
  justify-content: space-around;
}

